import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"PRD-013 — Landing page (root / orientation)","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-013.md","filePath":"prd/PRD-013.md"}'),n={name:"prd/PRD-013.md"};function r(s,e,l,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="prd-013-—-landing-page-root-orientation" tabindex="-1">PRD-013 — Landing page (root <code>/</code> orientation) <a class="header-anchor" href="#prd-013-—-landing-page-root-orientation" aria-label="Permalink to &quot;PRD-013 — Landing page (root \`/\` orientation)&quot;">​</a></h1><p><em>Orrery · Product Requirements · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Depends on:</strong> Issue #74 (this PRD); minor routing-decision note inline (no separate ADR — see §technical considerations). <strong>Slice:</strong> v0.6.x (post-Fleet) <strong>Screens affected:</strong> new <code>/</code> landing route (replaces the existing 307 redirect to <code>/explore</code>); logo <code>href</code> in <code>Nav.svelte</code> already points to <code>/</code> so no Nav change. <strong>Principles:</strong> physics first, attribution is design, mobile-first, share by URL (PA §principles). Why this is a PRD · Today <code>/</code> does a <code>307 → /explore</code> (<code>src/routes/+page.ts</code>). New users land directly in the 3D solar-system viewport with zero context: ten primary nav destinations, a Science encyclopedia, two station explorers, mission planner — none of which surface themselves on entry. Returning users get a cool view; first-timers get bewildered. This PRD defines a real orientation page that replaces the redirect.</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>A first-time visitor today opens <code>orrery.app</code>, the 307 fires, and they&#39;re dropped into a black canvas with planets orbiting a sun. The nav bar shows eleven labels — <code>EXPLORE · MISSIONS · FLEET · PLAN · FLY · EARTH · MOON · MARS · ISS · TIANGONG · SCIENCE</code> — and they have ~5 seconds to decide what&#39;s worth their attention before bouncing.</p><p>Returning users get the immediate-into-the-app behaviour they want (great). New users get nothing telling them:</p><ul><li>What is Orrery? A simulator? An encyclopedia? A planner? (Yes, all three — but they can&#39;t tell.)</li><li>Why does it exist? (Inspired by Artemis II, built to make spaceflight comprehensible. None of that surfaces.)</li><li>What can they actually do here? (The eleven nav labels are not self-explanatory — <code>PLAN</code> could be anything; <code>FLY</code> reads as a generic verb; <code>SCIENCE</code> is unspecific.)</li><li>Who built it, and what&#39;s the scope? (The footer&#39;s <code>Credits | Library | v0.3.0</code> lives in the corner and is monospaced 10 px — useful but not a substitute for an intro.)</li></ul><p>The site is small enough that we don&#39;t need a marketing page. We need an <strong>orientation page</strong> — a 1-screen scrollable narrative that explains the project in the same engineering-blueprint tone as <code>/science</code>&#39;s landing, then hands the user off to the right nav destination for whatever they actually wanted.</p><p>Marko&#39;s framing: <em>&quot;like 101 for this project — what is this, what are all the tabs, how to use it, motivation, goal. Make sure users can find their way.&quot;</em></p><p>This is the entrance, and right now there isn&#39;t one.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><p><strong>Primary — first-time visitor (curious lay person).</strong> Found Orrery via a link, search result, social media share, or word-of-mouth. Has a vague interest in space but no idea this app exists or what it does. Will spend 30–60 seconds deciding whether to engage further. Mobile-likely (search/share-link behaviour).</p><p><strong>Primary — first-time visitor (mission-curious enthusiast).</strong> Knows the difference between a Hohmann transfer and a free-return. Wants to find the parts of Orrery that surface real physics. Will scan for &quot;porkchop&quot;, &quot;ΔV&quot;, &quot;Kepler&quot;, &quot;EDL&quot;. Desktop-likely (this audience reads).</p><p><strong>Secondary — returning user.</strong> Has been here before. Doesn&#39;t want to read the intro again. Should be able to skip past it in one click — either via the nav (which is always-on) or via a prominent &quot;Explore now&quot; button.</p><p><strong>Secondary — educator / journalist.</strong> Wants the project&#39;s positioning, scope, and provenance for a reference or article. Will read more carefully than the curious visitor. Needs the credits/library/repo links visible.</p><p><strong>Out of audience.</strong> Astrodynamicists doing real work — they go straight to <code>/plan</code> or <code>/fly</code>. We don&#39;t optimise for them on the landing.</p><hr><h2 id="§promises" tabindex="-1">§promises <a class="header-anchor" href="#§promises" aria-label="Permalink to &quot;§promises&quot;">​</a></h2><p>The landing page promises:</p><ol><li><strong>30-second comprehension.</strong> A first-time visitor knows what Orrery is, why it exists, and what they can do here within the first 30 seconds (the hero + first scroll).</li><li><strong>All 11 nav destinations explained in one place.</strong> Each route gets a one-line &quot;what it does&quot; plus a deeper line of why it matters, in a single grid the user can scan.</li><li><strong>Honest about scope.</strong> The intro names what Orrery is <em>not</em> (not real flight planning, not a video game, not a marketing site for a space company), and links to the engineering decisions that constrain it (TA.md, ADR index in <code>/library</code>).</li><li><strong>Returning users skip past in one click.</strong> A prominent CTA at the top (&quot;Explore the solar system&quot;) goes straight to <code>/explore</code>. The nav stays sticky. No friction.</li><li><strong>Mobile parity.</strong> Same content, single column, same speed. No &quot;view full version on desktop&quot; prompts.</li><li><strong>All 14 supported locales.</strong> Every string goes through Paraglide; full editorial overlay coverage on day one. No locale falls back to en-US for the landing copy.</li><li><strong>Honest provenance footer.</strong> The existing <code>Credits | Library | v&lt;version&gt;</code> strip stays, plus inline links to GitHub, the README, and the Tech Authority doc.</li></ol><hr><h2 id="§scope" tabindex="-1">§scope <a class="header-anchor" href="#§scope" aria-label="Permalink to &quot;§scope&quot;">​</a></h2><h3 id="in-scope-v1" tabindex="-1">In scope (V1) <a class="header-anchor" href="#in-scope-v1" aria-label="Permalink to &quot;In scope (V1)&quot;">​</a></h3><p><strong>Hero.</strong> Wordmark (<code>ORRERY</code> 64–96 px), one-line tagline, two-line subhead, primary CTA (&quot;Explore the solar system&quot; → <code>/explore</code>), secondary CTA (&quot;How does it work?&quot; → scrolls to the encyclopedia preview lower on the page or links to <code>/science</code>).</p><p><strong>Section: What is this?</strong> 2–3 short paragraphs. &quot;Orrery is a browser-based solar system explorer, mission simulator, and encyclopedia. Real orbital mechanics, no backend, runs offline, in 14 languages.&quot; Honesty about what it isn&#39;t (not a flight planner; not a real-time sky chart; doesn&#39;t predict tomorrow&#39;s launch windows).</p><p><strong>Section: Why this exists.</strong> 2–3 short paragraphs on motivation. Inspired by Artemis II. Open source. No ads, no tracking, no accounts. Designed to be share-able by URL.</p><p><strong>Section: How to use it (guided tour).</strong> A short multi-paragraph walk-through naming the rough flow: start at <code>/explore</code> to see the system, click any planet to read its details, jump to <code>/missions</code> to find a real mission, hit <code>/plan</code> to see launch windows, follow it through to <code>/fly</code>, and use <code>/science</code> whenever a term confuses you. Each <code>/route</code> mention is a link.</p><p><strong>Grid: 11 nav destinations</strong> (10 primary nav + 1 supplementary <code>/library</code>). Each card:</p><ul><li>Route slug (<code>/explore</code>)</li><li>One-line &quot;what it is&quot; (e.g., &quot;The solar system in 3D&quot;)</li><li>One-line &quot;why you&#39;d use it&quot; (e.g., &quot;Real orbital mechanics, click any planet for live position data&quot;)</li><li>Single icon or small SVG (engineering-blueprint style, matches <code>/science</code> diagrams)</li><li>Click → navigates to the route</li></ul><p>The eleven cards in canonical order: <code>/explore · /plan · /fly · /missions · /earth · /moon · /mars · /iss · /tiangong · /science · /fleet</code>. (Fleet is in the nav; we list it.)</p><p><strong>Footer block.</strong> Bigger than the always-on <code>Credits | Library | v0.3.0</code> strip. Inline links: GitHub repo, README, License (MIT), Credits, Library, Privacy note (&quot;No accounts. No tracking. One functional cookie for explicit locale override per ADR-057&quot;).</p><p><strong>Locale picker remains accessible</strong> (sticks in nav per existing pattern). Language is auto-detected per #73 Gap 1; explicit picks persist per #73 Gap 2.</p><h3 id="out-of-scope-v1" tabindex="-1">Out of scope (V1) <a class="header-anchor" href="#out-of-scope-v1" aria-label="Permalink to &quot;Out of scope (V1)&quot;">​</a></h3><ul><li>Onboarding tour overlays / coachmarks / interactive tutorials.</li><li>A separate <code>/about</code> or <code>/privacy</code> route. The landing absorbs both.</li><li>Marketing imagery / animated hero (engineering-blueprint tone stays — no parallax, no lottie, no video bg).</li><li>Newsletter signup, contact form, anything requiring backend.</li><li>A/B testing scaffolding. Single canonical landing.</li><li>&quot;Sign in&quot; or any account UI.</li><li>Locale-specific landing variants beyond translation. Same structure for every locale.</li><li>Cookie-banner or &quot;we use cookies&quot; prompt — there is one strictly-necessary cookie per ADR-057, no consent required, prose disclosure in the footer block is sufficient.</li><li>A separate &quot;what&#39;s new in this version&quot; changelog feed — <code>/library</code> already serves this purpose for the link-provenance side; the GitHub releases page is the source of truth for changes.</li></ul><hr><h2 id="§design-hints" tabindex="-1">§design hints <a class="header-anchor" href="#§design-hints" aria-label="Permalink to &quot;§design hints&quot;">​</a></h2><h3 id="layout-desktop-≥-1024-px" tabindex="-1">Layout (desktop ≥ 1024 px) <a class="header-anchor" href="#layout-desktop-≥-1024-px" aria-label="Permalink to &quot;Layout (desktop ≥ 1024 px)&quot;">​</a></h3><ul><li>Single centred column, max-width ~880 px.</li><li>Vertical stack: Hero → What is this → Why this exists → Guided tour → 11-card grid (3 cols on ≥ 1024, 2 cols on 768–1023, 1 col on &lt; 768) → Footer block.</li><li>Top edge anchored to the existing 52 px nav. No nav changes.</li><li>Generous vertical rhythm — this page is supposed to feel like a real read, not a feature list.</li><li>Background: same <code>#04040c</code> as the rest of the app. No starfield decoration, no parallax (anti-pattern for the engineering-blueprint tone).</li></ul><h3 id="layout-mobile-375-px" tabindex="-1">Layout (mobile 375 px) <a class="header-anchor" href="#layout-mobile-375-px" aria-label="Permalink to &quot;Layout (mobile 375 px)&quot;">​</a></h3><ul><li>Same vertical order. Single column throughout. Cards stack to 1-up.</li><li>Hero scales: wordmark 48 px, tagline 18 px, body 14 px.</li><li>CTAs full-width buttons with 44 px touch targets per ADR-018.</li><li>No carousels, no horizontal scroll regions.</li></ul><h3 id="typography" tabindex="-1">Typography <a class="header-anchor" href="#typography" aria-label="Permalink to &quot;Typography&quot;">​</a></h3><ul><li>Hero wordmark: <code>var(--font-display)</code> (Bebas Neue), 96 px desktop / 48 px mobile, letter-spacing 8 px.</li><li>Section headings: Bebas Neue, 28–36 px, letter-spacing 3 px.</li><li>Body copy: <code>var(--font-editorial)</code> (Crimson Pro, italic per design system) for the why/what/tour paragraphs — lends the editorial weight the engineering-blueprint tone wants.</li><li>Card labels: <code>var(--font-display)</code> for route slug, <code>var(--font-mono)</code> (Space Mono) for the descriptions.</li></ul><h3 id="colour" tabindex="-1">Colour <a class="header-anchor" href="#colour" aria-label="Permalink to &quot;Colour&quot;">​</a></h3><ul><li>Primary text: <code>var(--color-text)</code> (off-white).</li><li>Body text dim: <code>rgba(255,255,255,0.78)</code>.</li><li>Card borders: <code>rgba(255,255,255,0.12)</code>, hover <code>rgba(78,205,196,0.4)</code> (teal accent).</li><li>Primary CTA button: teal accent border + transparent fill, hover fills.</li><li>Secondary CTA button: ghost (just text + border).</li><li>No new colour tokens; uses existing tokens.css palette.</li></ul><h3 id="card-design" tabindex="-1">Card design <a class="header-anchor" href="#card-design" aria-label="Permalink to &quot;Card design&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────┐</span></span>
<span class="line"><span>│  [icon]    /explore           │</span></span>
<span class="line"><span>│                               │</span></span>
<span class="line"><span>│  The solar system in 3D       │</span></span>
<span class="line"><span>│                               │</span></span>
<span class="line"><span>│  Real orbital mechanics,      │</span></span>
<span class="line"><span>│  click any planet for live    │</span></span>
<span class="line"><span>│  position data.               │</span></span>
<span class="line"><span>└───────────────────────────────┘</span></span></code></pre></div><p>Each card is an <code>&lt;a&gt;</code> with the full card hit-area as the click target. Hover: border tints teal, slight lift (4 px translateY transition).</p><h3 id="patterns" tabindex="-1">Patterns <a class="header-anchor" href="#patterns" aria-label="Permalink to &quot;Patterns&quot;">​</a></h3><ul><li>Buttons match the existing <code>.lens-toggle</code> / <code>.contrast-toggle</code> visual style for consistency with the nav chrome.</li><li>Section dividers: thin <code>1 px</code> rule in <code>rgba(255,255,255,0.08)</code> between major sections; no heavy boxes or panels.</li><li>Reduced-motion (<code>prefers-reduced-motion: reduce</code>) disables the card-hover translateY transition — same pattern as the rest of the app.</li></ul><hr><h2 id="§non-goals" tabindex="-1">§non-goals <a class="header-anchor" href="#§non-goals" aria-label="Permalink to &quot;§non-goals&quot;">​</a></h2><ul><li><strong>Not a marketing page.</strong> No &quot;Try Orrery now!&quot; buttons, no testimonials, no feature showcases, no pricing (it&#39;s free), no sign-up funnel.</li><li><strong>Not a documentation page.</strong> Anything beyond a paragraph belongs in <code>/science</code>, the README, or the docs site.</li><li><strong>Not a project status page.</strong> Build version is in the footer; live release notes belong on GitHub.</li><li><strong>Not a replacement for the README.</strong> The README is for people considering forking or contributing. The landing is for people who want to use the app.</li><li><strong>Not a tutorial.</strong> It points toward the parts of the app that are tutorials (<code>/science</code> Space-101, <code>/explore</code> exploration). It doesn&#39;t try to be one itself.</li><li><strong>Not a feature comparison.</strong> No &quot;Orrery vs Stellarium&quot; tables. We are what we are.</li></ul><hr><h2 id="§technical-considerations" tabindex="-1">§technical considerations <a class="header-anchor" href="#§technical-considerations" aria-label="Permalink to &quot;§technical considerations&quot;">​</a></h2><h3 id="routing-decision-no-separate-adr-needed" tabindex="-1">Routing decision (no separate ADR needed) <a class="header-anchor" href="#routing-decision-no-separate-adr-needed" aria-label="Permalink to &quot;Routing decision (no separate ADR needed)&quot;">​</a></h3><p>Today: <code>src/routes/+page.ts</code> does <code>redirect(307, &#39;\${base}/explore&#39;)</code>. This route was never locked by an ADR (verified: no ADR text mentions <code>/</code> → <code>/explore</code> as a binding decision). The redirect was an informal default while the landing was deferred.</p><p>Decision: <strong>delete <code>src/routes/+page.ts</code>, add <code>src/routes/+page.svelte</code>.</strong> No new ADR — this is a pure addition rather than a supersede of a locked decision. The change is documented inline in this PRD; the routing index in TA.md gets a single-line update noting <code>/</code> is the landing.</p><p>Logo <code>href</code> in <code>Nav.svelte</code> already points to <code>/</code> via <code>withLang(\\</code>\${base}/\`, activeLocale)\` — no Nav change needed.</p><h3 id="implementation-surface" tabindex="-1">Implementation surface <a class="header-anchor" href="#implementation-surface" aria-label="Permalink to &quot;Implementation surface&quot;">​</a></h3><ul><li><code>src/routes/+page.svelte</code> (new) — the landing component.</li><li><code>src/routes/+page.ts</code> (delete or replace with <code>export const prerender = true;</code> — same as other routes; SvelteKit will use the default load).</li><li><code>messages/en-US.json</code> — add ~30–60 keys under the <code>landing_*</code> prefix (matches <code>science_*</code> / <code>iss_*</code> / <code>tiangong_*</code> convention).</li><li><code>messages/{es,fr,de,pt-BR,it,nl,zh-CN,ja,ko,hi,ar,ru,sr-Cyrl}.json</code> — add the same keys, translated. Manual rollout per the v0.5.x Dutch wave pattern.</li><li><code>tests/e2e/landing.spec.ts</code> (new) — covers: page loads, hero renders, primary CTA navigates to <code>/explore</code>, all 11 cards render with correct slugs and descriptions, mobile 375 px layout (cards single-column), Lighthouse accessibility ≥ 95.</li><li><code>scripts/capture-screenshots.ts</code> — add a <code>01-landing.png</code> shot at the top of the deck; renumber existing shots accordingly.</li><li><code>docs/screenshots/</code> — regenerate all shots after numbering shift.</li><li><code>README.md</code> — update the screenshot reference if numbering changed; add a one-line note that <code>/</code> is now the landing.</li><li><code>docs/user-guide.md</code> — same one-line note.</li><li><code>IMPLEMENTATION.md</code> — add v0.6.x slice entry for #74.</li><li><code>CHANGELOG.md</code> — <code>[Unreleased]</code> entry under <code>Added</code>.</li></ul><h3 id="locale-flow" tabindex="-1">Locale flow <a class="header-anchor" href="#locale-flow" aria-label="Permalink to &quot;Locale flow&quot;">​</a></h3><ul><li>Landing copy goes through Paraglide like every other route. Auto-detect (per #73 Gap 1) gives a German-browser visitor German landing text on first paint. URL canonicalisation rewrites <code>/</code> to <code>/?lang=de</code>.</li><li>Cookie persistence (per #73 Gap 2) is unaffected — the landing doesn&#39;t write any new state.</li></ul><h3 id="performance-budget" tabindex="-1">Performance budget <a class="header-anchor" href="#performance-budget" aria-label="Permalink to &quot;Performance budget&quot;">​</a></h3><ul><li>Total page weight under 80 KB (HTML + CSS + 11 inline SVG icons). No heavy images, no fonts beyond the already-loaded Bebas Neue + Crimson Pro + Space Mono. No client-side JS beyond what <code>+layout.svelte</code> loads.</li><li>LCP target: &lt; 1.0 s on a fast 3G profile (the page is mostly text + small SVG; should easily clear).</li><li>No new third-party assets.</li></ul><h3 id="url-structure" tabindex="-1">URL structure <a class="header-anchor" href="#url-structure" aria-label="Permalink to &quot;URL structure&quot;">​</a></h3><ul><li>Canonical landing is <code>/</code>. Locale-stamped form is <code>/?lang=&lt;code&gt;</code>.</li><li>Card-clicks navigate to the canonical route URLs (<code>/explore</code>, <code>/plan</code>, etc.) using the same <code>withLang(...)</code> helper as the Nav.</li></ul><h3 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h3><ul><li>The landing page is HTML at the root URL. Already prerendered via adapter-static; no extra SEO work needed beyond a sensible <code>&lt;title&gt;</code> (<code>Orrery · A solar system explorer for the browser</code>) and <code>&lt;meta description&gt;</code> (~150 chars).</li><li>Localised <code>&lt;title&gt;</code> and <code>&lt;meta&gt;</code> per locale (already supported by the existing <code>&lt;svelte:head&gt;</code> pattern).</li></ul><h3 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h3><ul><li>Single <code>&lt;h1&gt;</code> (the wordmark or the tagline). Subsequent sections use <code>&lt;h2&gt;</code> / <code>&lt;h3&gt;</code>.</li><li>Card grid is a <code>&lt;ul&gt;</code> with each card as a <code>&lt;li&gt;</code> containing an <code>&lt;a&gt;</code> (semantic, screen-reader-friendly).</li><li>All decorative SVGs have <code>aria-hidden=&quot;true&quot;</code>.</li><li>Primary CTA is a <code>&lt;button&gt;</code> styled as a button (or <code>&lt;a&gt;</code> with role appropriate to the nav target).</li><li>Lighthouse a11y target ≥ 95 (parity with the rest of the app per ADR-025).</li><li>Reduced-motion respected.</li><li>RTL (Arabic) renders correctly — verified via existing <code>[dir=&quot;rtl&quot;]</code> CSS hooks.</li></ul><hr><h2 id="§definition-of-done" tabindex="-1">§definition-of-done <a class="header-anchor" href="#§definition-of-done" aria-label="Permalink to &quot;§definition-of-done&quot;">​</a></h2><ul><li>[ ] PRD-013 (this doc) reviewed and approved.</li><li>[ ] UXS-013 reviewed and approved.</li><li>[ ] <code>src/routes/+page.svelte</code> implemented; <code>+page.ts</code> updated to remove the redirect.</li><li>[ ] All landing strings live in <code>messages/en-US.json</code> under the <code>landing_*</code> prefix.</li><li>[ ] All 14 locales have full translations of the landing strings (no en-US fallback gaps).</li><li>[ ] <code>npm run preflight</code> clean (typecheck + lint + test + validate-data + build).</li><li>[ ] <code>tests/e2e/landing.spec.ts</code> green on desktop-chromium + mobile-chromium.</li><li>[ ] Mobile 375 px verified — single-column card layout, hero scales, no horizontal scroll.</li><li>[ ] Lighthouse accessibility ≥ 95 on the new route.</li><li>[ ] Screenshots regenerated; README updated if numbering shifted.</li><li>[ ] CHANGELOG entry under <code>[Unreleased]</code>.</li><li>[ ] <code>IMPLEMENTATION.md</code> updated with the v0.6.x slice entry.</li><li>[ ] <code>docs/user-guide.md</code> updated with the one-line &quot;what&#39;s at /&quot; note.</li><li>[ ] TA.md routing table touched if relevant.</li><li>[ ] Logo click in Nav still goes to the landing (verified — already does via <code>href={withLang(&#39;\${base}/&#39;, activeLocale)}</code>).</li><li>[ ] CTA &quot;Explore the solar system&quot; navigates to <code>/explore?lang=&lt;active&gt;</code> correctly.</li></ul><hr><p><em>Draft v0.1 · awaiting review.</em></p>`,77)])])}const g=o(n,[["render",r]]);export{u as __pageData,g as default};
